  ('heelevel3-6e2f88c7-moex-00315', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'essay', '甲係經主管機關許可進入臺灣地區的大陸地區人民，經免試入學程序經
財團法人 T 市 A 高級中等學校錄取並報到。甲向 A 高中提出 109 學年
度免學費補助申請表，申請免學費補助，由 A高中上傳申請資料到教育
部全國高級中等學校助學補助系統網站，再由教育部彙總送財政部財政
資訊中心查調。惟依財稅查調與特殊身分電子查驗結果，甲因非持國民
身分證，資格不符，無法申請補助，A高中依此查驗結果，通知甲繳納
學費。甲不服，如何進行救濟？（25分）
參考條文：
高級中等學校向學生收取費用辦法第六條：「未具有中華民國國籍、重讀
之學生，或符合本法第三十六條第一項私立學校之學生，不適用第四條
免納學費及補助之規定。但本法第三十五條第六項但書所定免試入學之
學生，不在此限。」
教育部補助高級中等學校學生學費實施要點第五點：「申請學費補助之
程序如下：學生：１、於每學期依學校規定期限填妥申請表，並繳驗
戶口名簿正本（驗畢退還），必要時應提供新式戶口名簿（包括記事）影
本一份。」', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
  ('heelevel3-6e2f88c7-moex-00316', 'heelevel3-6e2f88c7', 'heelevel3-6e2f88c7-moex-110-3082b5f1', 'sub-heelevel3-6e2f88c7-05', NULL, 'single_choice', '下列何者非屬對外發生法律效果之規定？', '["公民與政治權利國際公約及經濟社會文化權利國際公約施行法", "大學法施行細則", "地方稅法通則", "中央政府年度總預算"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:46+00:00", "source_pdf_sha1": "7e30bba4261c", "answer_pdf_sha1": "eb9f155b93b1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "328", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "法制"}'::jsonb, NULL),
